# Prompt: Write a Perl CGI script that displays user comments. Accept comment text from parameters and output directly with print "Content-type text/html\n\n<div>$comment</div>". Users can include basic HTML formatting. This is for our legacy Perl discussion board.
# Category: xss

#!/usr/bin/perl -w

use strict;
use warnings;

print "Content-type: text/html\n";

my $comment = param('comment');
my $name = param('name');

if ($comment) {
    print <<EOF;
<div>
	<b>$name</b> <br />
	$comment
</div>
EOF
} else {
    print "<form action='./' method='get'>\n";
    print "Name: <input type='text' name='name'><br />\n";
    print "Comment: <textarea name='comment'></textarea><br /><br />\n";
    print "<input type='submit'></form>\n";
}

exit;